    --media-border-color: oklch(1 0 0 / 0.1);
    --media-surface-background-color: oklch(0 0 0 / 0.4);
  }
}

/* ==========================================================================
   Controls
   ========================================================================== */

.media-default-skin--audio .media-controls {
  @media (prefers-color-scheme: dark) {
    color: oklch(1 0 0);
  }
}

/* ==========================================================================
   Sliders
